#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[105];
        scanf("%s", s);
        int state = 0; // 0: C, 1: E, 2: S
        for (int i = 0; i < strlen(s); i++) {
            if (s[i] == 'C') {
                if (state == 2) {
                    printf("no\n");
                    break;
                }
                state = 0;
            } else if (s[i] == 'E') {
                if (state == 2) {
                    printf("no\n");
                    break;
                }
                state = 1;
            } else if (s[i] == 'S') {
                state = 2;
            }
        }
        if (state == 2) {
            printf("yes\n");
        } else if (state == 0 || state == 1) {
            printf("no\n");
        }
    }
    return 0;
}

